
import { IPaneMap } from './../../interfaces/IEditor';

export const searchPane = (pane: IPaneMap, matchingId: string, parent: IPaneMap|null = null): {pane: IPaneMap|null, parent: IPaneMap|null}|null => {
    if (pane.id == matchingId) {
        return {pane, parent};
    } else {
        let result: {pane: IPaneMap|null, parent: IPaneMap|null}|null = null;
        if (pane.primaryPane) {
            result = searchPane(pane.primaryPane, matchingId, pane);
            if (result) {
                return result;
            }
        }
        if (pane.secondaryPane) {
            result = searchPane(pane.secondaryPane, matchingId, pane);
            if (result) {
                return result;
            }
        }
        return null;
    }
}