const prefixKey = 'zane.';
export class LocalStorageUtil {

    static setItem(key: string, value: string) {
        if (window.localStorage) {
            try {
                window.localStorage.setItem(prefixKey + key, value)
            } catch (err) {}
        } else {
            let exp = new Date();
            exp.setTime(exp.getTime() + 365 * 24 * 60 * 60 * 1e3);
            document.cookie = prefixKey + key + "=" + value + ";expires=" + exp.toUTCString()
        }
    }

    static getItem(key: string) {
        if (window.localStorage) {
            return window.localStorage.getItem(prefixKey + key)
        } else {
            let arr = document.cookie.match(new RegExp("(^| )" + prefixKey + key + "=([^;]*)(;|$)"));
            if (arr != null) {
                return arr[2]
            }
        }
        return null
    }

    static removeItem(key: string) {
        if (window.localStorage) {
            window.localStorage.removeItem(prefixKey + key)
        } else {
            let exp = new Date();
            exp.setTime(exp.getTime() - 1);
            let cval = LocalStorageUtil.getItem(key);
            if (cval != null) {
                document.cookie = prefixKey + key + "=" + cval + ";expires=" + exp.toUTCString()
            }
        }
    }
}
