import * as React from "react";
import { Provider } from 'react-redux';
import { message } from "antd";
import createStore from './store/store';
import AppRouter from "./AppRouter";
import './App.scss';

message.config({
    top: 100,
    duration: 5,
    maxCount: 3
});

const store = createStore();

const App: React.FC = () => {
    return (
        <Provider store={store}>
            <AppRouter />
        </Provider>
    );
};

export default App;
