import { IBlogNav } from "../interfaces/IBlog";
import { generateTreeItemData } from "./utils/generateTreeItemData";
import { 
    UPDATE_BLOG_NAV_TREE_CONFIG,
    UPDATE_BLOG_CONFIG_SHA
} from "../constants/actions/blogActionTypes";

const zanejs = (window as any).zanejs;

/**
 * 获取博文导航数据
 */
export const getBlogNavData = () => {
    return (dispatch: Function, getState: Function) => {
        fetch(`${process.env.PUBLIC_URL}/assets/config/blog.json?r=${zanejs.utils.randomCharacters(10)}`)
        .then(response => {
            response.json().then(result => {
                let navTreeData: any[] = [];
                if (result) {
                    result.map((item: IBlogNav, index: number) => {
                        navTreeData.push(generateTreeItemData(item, `key-${index}`));
                    });
                }
                dispatch(updateBlogNavTreeConfig({navTreeData}));
            });
        })
    }
};

export const updateBlogNavTreeConfig = (payload: any) => {
    return (dispatch: Function, getState: Function) => {
        dispatch({
            type: UPDATE_BLOG_NAV_TREE_CONFIG,
            payload: { ...payload }
        });
    }
};

export const updateBlogSha = (sha: string) => {
    return (dispatch: Function, getState: Function) => {
        dispatch({
            type: UPDATE_BLOG_CONFIG_SHA,
            payload: { sha }
        });
    }
};
